function useWidth(){
  const [w,setW]=useState(typeof window!=="undefined"?window.innerWidth:1024);
  useEffect(()=>{const h=()=>setW(window.innerWidth);window.addEventListener("resize",h);return()=>window.removeEventListener("resize",h);},[]);
  return w;
}

/* ══════════════════════════════════════════════════════════
   POPUP COMPONENT
══════════════════════════════════════════════════════════ */
function LeadPopup({t, gold, rose, grad, onClose}){
  const [prenom,setPrenom]=useState("");
  const [nom,setNom]=useState("");
  const [email,setEmail]=useState("");
  const [p1,setP1]=useState("");
  const [p2,setP2]=useState("");
  const [status,setStatus]=useState("idle"); // idle | sending | success | error
  const [errMsg,setErrMsg]=useState("");

  const submit = async () => {
    if(!prenom||!nom||!email||!p1||!p2){ setErrMsg(t.popup_required); return; }
    setStatus("sending"); setErrMsg("");
    try {
      const res = await fetch(`https://formspree.io/f/${FORMSPREE_ID}`, {
        method:"POST",
        headers:{"Content-Type":"application/json","Accept":"application/json"},
        body: JSON.stringify({
          prenom, nom, email,
          parfum_1: p1, parfum_2: p2,
          _subject: `Nouvelle inscription Belle & ReBelle — ${prenom} ${nom}`
        })
      });
      if(res.ok){ setStatus("success"); }
      else { setStatus("error"); }
    } catch { setStatus("error"); }
  };

  const isMobile = typeof window !== "undefined" && window.innerWidth < 700;

  if(status==="success") return (
    <div style={{position:"fixed",inset:0,zIndex:400,background:"rgba(45,31,26,0.7)",backdropFilter:"blur(10px)",display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
      <div style={{background:"#fff",maxWidth:420,width:"100%",padding:isMobile?"32px 24px":"44px 40px",textAlign:"center",boxShadow:"0 24px 64px rgba(0,0,0,0.18)"}}>
        <div style={{fontSize:48,marginBottom:16}}>✨</div>
        <h3 style={{fontSize:26,fontStyle:"italic",fontWeight:400,color:"#2d1f1a",marginBottom:12}}>{t.popup_success_title}</h3>
        <p style={{color:"#7a5a50",lineHeight:1.9,fontSize:14,marginBottom:28}}>{t.popup_success_msg}</p>
        <button onClick={onClose} style={{background:grad,border:"none",color:"#fff",padding:"13px 32px",fontSize:11,letterSpacing:3,textTransform:"uppercase",cursor:"pointer",fontFamily:"inherit",fontWeight:600}}>{t.popup_success_close}</button>
      </div>
    </div>
  );

  return (
    <div style={{position:"fixed",inset:0,zIndex:400,background:"rgba(45,31,26,0.65)",backdropFilter:"blur(10px)",display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{background:"#fff",maxWidth:500,width:"100%",position:"relative",boxShadow:"0 28px 72px rgba(0,0,0,0.2)",maxHeight:"94vh",overflowY:"auto"}}>

        {/* Top banner */}
        <div style={{background:grad,padding:"20px 28px",textAlign:"center",position:"relative"}}>
          <button onClick={onClose} style={{position:"absolute",top:12,right:16,background:"none",border:"none",color:"rgba(255,255,255,0.7)",fontSize:20,cursor:"pointer",lineHeight:1}}>✕</button>
          <div style={{fontSize:28,marginBottom:6}}>🌸</div>
          <h3 style={{fontSize:isMobile?18:22,fontStyle:"italic",fontWeight:400,color:"#fff",lineHeight:1.3}}>{t.popup_title}</h3>
        </div>

        <div style={{padding:isMobile?"20px 18px":"28px 32px"}}>
          {/* Incentive */}
          <div style={{background:"rgba(201,149,106,0.08)",border:"1px solid rgba(201,149,106,0.25)",padding:"10px 16px",marginBottom:22,textAlign:"center",fontSize:13,color:"#7a5a50",fontStyle:"italic"}}>
            {t.popup_incentive}
          </div>
          <p style={{color:"#9a7060",fontSize:13,lineHeight:1.7,marginBottom:22,textAlign:"center"}}>{t.popup_sub}</p>

          {/* Fields */}
          <div style={{display:"grid",gridTemplateColumns:isMobile?"1fr":"1fr 1fr",gap:12,marginBottom:12}}>
            <div>
              <label style={{fontSize:10,letterSpacing:2,color:gold,textTransform:"uppercase",display:"block",marginBottom:5}}>{t.popup_prenom}</label>
              <input value={prenom} onChange={e=>setPrenom(e.target.value)} placeholder="Emmanuelle" style={{width:"100%",padding:"10px 12px",border:"1.5px solid rgba(201,149,106,0.25)",background:"#fdf8f3",color:"#2d1f1a",fontSize:13,fontFamily:"inherit",outline:"none",boxSizing:"border-box"}}/>
            </div>
            <div>
              <label style={{fontSize:10,letterSpacing:2,color:gold,textTransform:"uppercase",display:"block",marginBottom:5}}>{t.popup_nom}</label>
              <input value={nom} onChange={e=>setNom(e.target.value)} placeholder="Saillet" style={{width:"100%",padding:"10px 12px",border:"1.5px solid rgba(201,149,106,0.25)",background:"#fdf8f3",color:"#2d1f1a",fontSize:13,fontFamily:"inherit",outline:"none",boxSizing:"border-box"}}/>
            </div>
          </div>

          <div style={{marginBottom:12}}>
            <label style={{fontSize:10,letterSpacing:2,color:gold,textTransform:"uppercase",display:"block",marginBottom:5}}>{t.popup_email}</label>
            <input type="email" value={email} onChange={e=>setEmail(e.target.value)} placeholder="votre@email.com" style={{width:"100%",padding:"10px 12px",border:"1.5px solid rgba(201,149,106,0.25)",background:"#fdf8f3",color:"#2d1f1a",fontSize:13,fontFamily:"inherit",outline:"none",boxSizing:"border-box"}}/>
          </div>

          <div style={{display:"grid",gridTemplateColumns:isMobile?"1fr":"1fr 1fr",gap:12,marginBottom:20}}>
            <div>
              <label style={{fontSize:10,letterSpacing:2,color:gold,textTransform:"uppercase",display:"block",marginBottom:5}}>{t.popup_p1}</label>
              <select value={p1} onChange={e=>setP1(e.target.value)} style={{width:"100%",padding:"10px 12px",border:"1.5px solid rgba(201,149,106,0.25)",background:"#fdf8f3",color:p1?"#2d1f1a":"#b5a090",fontSize:12,fontFamily:"inherit",outline:"none",boxSizing:"border-box"}}>
                <option value="">{t.popup_choose}</option>
                {PARFUM_NAMES.map(n=><option key={n} value={n}>{n}</option>)}
              </select>
            </div>
            <div>
              <label style={{fontSize:10,letterSpacing:2,color:gold,textTransform:"uppercase",display:"block",marginBottom:5}}>{t.popup_p2}</label>
              <select value={p2} onChange={e=>setP2(e.target.value)} style={{width:"100%",padding:"10px 12px",border:"1.5px solid rgba(201,149,106,0.25)",background:"#fdf8f3",color:p2?"#2d1f1a":"#b5a090",fontSize:12,fontFamily:"inherit",outline:"none",boxSizing:"border-box"}}>
                <option value="">{t.popup_choose}</option>
                {PARFUM_NAMES.filter(n=>n!==p1).map(n=><option key={n} value={n}>{n}</option>)}
              </select>
            </div>
          </div>

          {errMsg && <p style={{color:rose,fontSize:12,marginBottom:12,textAlign:"center"}}>{errMsg}</p>}
          {status==="error" && <p style={{color:rose,fontSize:12,marginBottom:12,textAlign:"center"}}>{t.popup_error}</p>}

          <button onClick={submit} disabled={status==="sending"} style={{width:"100%",background:status==="sending"?"rgba(201,149,106,0.5)":grad,border:"none",color:"#fff",padding:"14px",fontSize:11,letterSpacing:3,textTransform:"uppercase",cursor:status==="sending"?"not-allowed":"pointer",fontFamily:"inherit",fontWeight:600,marginBottom:12}}>
            {status==="sending"?t.popup_sending:t.popup_submit}
          </button>

          <button onClick={onClose} style={{width:"100%",background:"transparent",border:"none",color:"#b5a090",fontSize:11,cursor:"pointer",fontFamily:"inherit",textDecoration:"underline",padding:"4px"}}>
            {t.popup_skip}
          </button>

          <p style={{fontSize:10,color:"#c5b5a5",textAlign:"center",marginTop:14,lineHeight:1.6}}>
            🔒 Vos données sont confidentielles. Aucune revente. Désinscription possible à tout moment.
          </p>
        </div>
      </div>
    </div>
  );
}

